#include <stdio.h>

unsigned int bit_and(unsigned int a, unsigned int b) {
    return a & b;
}

unsigned int bit_or(unsigned int a, unsigned int b) {
    return a | b;
}

unsigned int bit_xor(unsigned int a, unsigned int b) {
    return a ^ b;
}

unsigned int bit_not(unsigned int a) {
    return (~a) & 0xFF;
}

unsigned int bit_shift_left(unsigned int a, int n) {
    return (a << n) & 0xFF;
}

unsigned int bit_shift_right(unsigned int a, int n) {
    return a >> n;
}

validation.test_code:
void test_bit_and(void) {
    TEST_ASSERT_EQUAL_INT(0x05, bit_and(0xA5, 0x0F));
    TEST_ASSERT_EQUAL_INT(0x00, bit_and(0xA5, 0x50));
    TEST_ASSERT_EQUAL_INT(0xFF, bit_and(0xFF, 0xFF));
    TEST_ASSERT_EQUAL_INT(0x00, bit_and(0x00, 0xFF));
}

void test_bit_or(void) {
    TEST_ASSERT_EQUAL_INT(0xAF, bit_or(0xA5, 0x0F));
    TEST_ASSERT_EQUAL_INT(0xF5, bit_or(0xA5, 0x50));
    TEST_ASSERT_EQUAL_INT(0xFF, bit_or(0xFF, 0x00));
    TEST_ASSERT_EQUAL_INT(0x0F, bit_or(0x00, 0x0F));
}

void test_bit_xor(void) {
    TEST_ASSERT_EQUAL_INT(0xAA, bit_xor(0xA5, 0x0F));
    TEST_ASSERT_EQUAL_INT(0xF5, bit_xor(0xA5, 0x50));
    TEST_ASSERT_EQUAL_INT(0xFF, bit_xor(0xFF, 0x00));
    TEST_ASSERT_EQUAL_INT(0xFF, bit_xor(0x00, 0xFF));
}

void test_bit_not(void) {
    TEST_ASSERT_EQUAL_INT(0x5A, bit_not(0xA5));
    TEST_ASSERT_EQUAL_INT(0x00, bit_not(0xFF));
    TEST_ASSERT_EQUAL_INT(0xFF, bit_not(0x00));
    TEST_ASSERT_EQUAL_INT(0xAF, bit_not(0x50));
}

void test_bit_shift_left(void) {
    TEST_ASSERT_EQUAL_INT(0x94, bit_shift_left(0xA5, 2));
    TEST_ASSERT_EQUAL_INT(0xA0, bit_shift_left(0x50, 1));
    TEST_ASSERT_EQUAL_INT(0x00, bit_shift_left(0xFF, 1));
    TEST_ASSERT_EQUAL_INT(0x04, bit_shift_left(0x01, 2));
}

void test_bit_shift_right(void) {
    TEST_ASSERT_EQUAL_INT(0x29, bit_shift_right(0xA5, 2));
    TEST_ASSERT_EQUAL_INT(0x28, bit_shift_right(0xA0, 2));
    TEST_ASSERT_EQUAL_INT(0x7F, bit_shift_right(0xFF, 1));
    TEST_ASSERT_EQUAL_INT(0x00, bit_shift_right(0x01, 2));
}

int main(void) {
    RUN_TEST(test_bit_and);
    RUN_TEST(test_bit_or);
    RUN_TEST(test_bit_xor);
    RUN_TEST(test_bit_not);
    RUN_TEST(test_bit_shift_left);
    RUN_TEST(test_bit_shift_right);
    TEST_SUMMARY();
    return _clings_failures > 0 ? 1 : 0;
}

